<template>
    <div>
      <el-card>
        <el-form label-width="100px" size="mini">
            <el-form-item label="转入卡号">
              <el-input v-model="form.idcard_to"></el-input>
            </el-form-item>
            <el-form-item label="转入姓名">
              <el-input v-model="form.name_to"></el-input>
            </el-form-item>
            <el-form-item label="转账（元）">
              <el-input type="number" v-model="form.account"></el-input>
            </el-form-item>
        </el-form>
        <el-form label-width="80px" size="mini">
            <div style="text-align: center;">
                <el-button type="primary" @click="submit">提交</el-button>
            </div>
        </el-form>
      </el-card>

      <el-card v-if="info['余额']">
        <p>操作：{{info['操作']}}</p>
        <p>转入姓名：{{info['转入姓名']}}</p>
        <p>转入账号：{{info['转入账号']}}</p>
        <p>余额：{{info['余额']}}元</p>
        
      </el-card>
        
    </div>
  </template>
  
  <script>
    import {
      userfunTransfer, // 转账
  } from '@/api/index'
  
    export default {
      data() {
        return {
          form: {},
          info: {}
        }
      },
      mounted(){

      },
      methods: {
        // 转账
        async submit(){
            let page = {...this.form}
            let res = await userfunTransfer(page)
            if(res['余额']){
                this.info = res
            }
        },
      }
    }
  </script>
  
  <style scoped>

    /deep/.el-card{
      margin-top: 10px;
    }
  </style>
  
  


